-- Coach Store List - Auto-generated from FY26 January Store List.csv
-- 755 stores total

-- Create stores table
create table if not exists stores (
  id uuid primary key default gen_random_uuid(),
  store_number text unique not null,
  store_name text not null,
  status text not null default 'OPEN',
  channel text not null default 'RCCH',
  region text,
  region_manager text,
  district text,
  district_manager text,
  area text,
  area_manager text,
  street_address text,
  building_suite text,
  city text,
  state text,
  zip_code text,
  country text not null default 'USA',
  phone text,
  fax text,
  voicemail text,
  opening_date date,
  closed_date date,
  registers_quantity integer,
  number_of_wraps integer,
  people_hub_code text,
  fms_site_id text,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

-- Add store_id FK to app_users
alter table app_users add column if not exists store_id uuid references stores(id);

-- Updated-at trigger
drop trigger if exists trg_stores_updated on stores;
create trigger trg_stores_updated before update on stores for each row execute function update_updated_at();

-- RLS
alter table stores enable row level security;
drop policy if exists "Service role full access" on stores;
drop policy if exists "Anon read stores" on stores;
create policy "Service role full access" on stores for all using (true) with check (true);
create policy "Anon read stores" on stores for select using (true);

